@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<div class="container py-4">
    <h1>Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-primary w-100" @onclick="ApplyFilters">Search</button>
        </div>
    </div>

    @if (courses.Any())
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in courses)
                    {
                        <tr>
                            <td>@course.CourseCode</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? departmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();
    private string searchTerm = string.Empty;
    private int selectedDepartmentId;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        selectedDepartmentId = departmentId ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        int? deptFilter = selectedDepartmentId > 0 ? selectedDepartmentId : null;
        courses = CatalogService.GetCourses(searchTerm, deptFilter);
    }
}

